import{_ as l,C as i,o as A,c as g,j as E,a as e,b as r,w as n,E as o,a4 as B,a5 as s}from"./chunks/framework.sOZL8giL.js";const m=JSON.parse('{"title":"范式转移","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/01-范式转移.md","filePath":"01-Harness工程核心原则/01-范式转移.md","lastUpdated":1774181700000}'),p={name:"01-Harness工程核心原则/01-范式转移.md"};function d(u,t,h,D,C,b){const a=i("Mermaid");return A(),g("div",null,[t[2]||(t[2]=E("h1",{id:"范式转移",tabindex:"-1"},[e("范式转移 "),E("a",{class:"header-anchor",href:"#范式转移","aria-label":'Permalink to "范式转移"'},"​")],-1)),t[3]||(t[3]=E("blockquote",null,[E("p",null,[e("本章是 "),E("strong",null,"Hermes Engineering 系列"),e("第 1 模块的第 1 章。")])],-1)),t[4]||(t[4]=E("p",null,"当代码可以被无限生成，工程师的价值就从「写代码」迁移到了「设计让代码产生的环境」。这不是科幻小说——OpenAI 团队用一个三人团队、五个月时间，构建了一个百万行代码的复杂系统，期间大约合并了 1500 个 PR。后来团队扩展到七人，人均产出反而提升了。",-1)),t[5]||(t[5]=E("p",null,"这就是 Harness Engineering——软件工程正在经历的一次范式转移。",-1)),(A(),r(B,null,{default:n(()=>[o(a,{id:"mermaid-14",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%BB%A3%E7%A0%81%E7%94%9F%E6%88%90%E6%88%90%E6%9C%AC%E8%B6%8B%E8%BF%91%E4%BA%8E%E9%9B%B6%5D%20--%3E%20B%5B%E5%B7%A5%E7%A8%8B%E5%B8%88%E8%A7%92%E8%89%B2%E8%BD%AC%E5%8F%98%5D%0A%20%20%20%20B%20--%3E%20C%5B%E4%BB%8E%E6%B3%A5%E7%93%A6%E5%8C%A0%20%E2%86%92%20%E7%B3%BB%E7%BB%9F%E8%AE%BE%E8%AE%A1%E5%B8%88%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%B7%A5%E7%A8%8B%E5%B8%88%E5%8F%AA%E5%89%A9%E4%B8%89%E4%BB%B6%E4%BA%8B%5D%0A%20%20%20%20D%20--%3E%20E%5B%E8%AE%BE%E8%AE%A1%E7%8E%AF%E5%A2%83%5D%0A%20%20%20%20D%20--%3E%20F%5B%E6%98%8E%E7%A1%AE%E6%84%8F%E5%9B%BE%5D%0A%20%20%20%20D%20--%3E%20G%5B%E6%9E%84%E5%BB%BA%E5%8F%8D%E9%A6%88%5D%0A%20%20%20%20E%20--%3E%20H%5BHarness%20Engineering%20%E8%8C%83%E5%BC%8F%5D%0A%20%20%20%20F%20--%3E%20H%0A%20%20%20%20G%20--%3E%20H%0A%20%20%20%20H%20--%3E%20I%5B%E4%BB%A3%E7%A0%81%20%3D%20%E5%BB%89%E4%BB%B7%E7%BC%96%E8%AF%91%E4%BA%A7%E7%89%A9%5D%0A%20%20%20%20H%20--%3E%20J%5B%E7%8E%AF%E5%A2%83%20%3D%20%E6%A0%B8%E5%BF%83%E8%B5%84%E4%BA%A7%5D%0A"})]),fallback:n(()=>[...t[0]||(t[0]=[e(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=s('<blockquote><p>💡 <strong>图解：</strong> 代码从&quot;稀缺资产&quot;降级为&quot;可再生资源&quot;，工程师的核心价值从写代码本身转移到了制造代码的环境。</p></blockquote><hr><h2 id="agent-不是笨-是瞎" tabindex="-1">Agent 不是笨，是瞎 <a class="header-anchor" href="#agent-不是笨-是瞎" aria-label="Permalink to &quot;Agent 不是笨，是瞎&quot;">​</a></h2><p>早期的进展其实很慢。但原因不是模型不够强，而是<strong>环境定义不足</strong>。</p><p>Agent 缺什么？工具、对系统架构的认知、上下文。真正的瓶颈不是模型智商不够，而是工程结构没搭好。Harness 就是为了解决这个问题而诞生的——它不仅仅是让 AI 写代码，而是构建一个系统，让 AI 可以稳定、可控、可验证地工作。</p><p>当 Agent 犯错时，第一反应不应该是去修代码，而是问：<strong>环境里缺了什么信息，导致 Agent 犯了这个错误？</strong> 是提示词没写清楚？是测试用例覆盖不足？还是工具链报错不明显？</p><p>你是在调试 Agent，而不是在调试程序。</p><hr><h2 id="工程师角色的转变" tabindex="-1">工程师角色的转变 <a class="header-anchor" href="#工程师角色的转变" aria-label="Permalink to &quot;工程师角色的转变&quot;">​</a></h2><p>在传统的软件工程里，工程师是泥瓦匠，关心每一行代码的语法，关心每一块砖。但在 Harness Engineering 里，工程师变成了<strong>系统设计师</strong>。</p><p>代码的属性变了——以前代码是昂贵的资产，现在代码变成了廉价的编译产物，像打印出来的纸一样，随时可以生成，随时可以丢弃。</p><p>Harness 工程师的核心职责只剩三件事：</p><p><strong>1. 设计环境</strong>——给 Agent 搭好脚手架：仓库结构、CI 流水线、Lint 规则、开发者工具。没有这些，Agent 就是在一片荒地上盖房子。</p><p><strong>2. 明确意图</strong>——把需求拆解成 Agent 能理解的、无歧义的规范。不是&quot;帮我写个功能&quot;，而是足够清晰的语言告诉 Agent 你到底想要什么。</p><p><strong>3. 构建反馈</strong>——这是最关键的一环。Agent 自我审查、静态检查、集成测试，让 Agent 在提交代码前在这个闭环里自己跑通。这不是提示词工程，这是<strong>反馈闭环工程</strong>。</p><hr><h2 id="打破人月神话" tabindex="-1">打破人月神话 <a class="header-anchor" href="#打破人月神话" aria-label="Permalink to &quot;打破人月神话&quot;">​</a></h2><p>这打破了软件工程经典著作《人月神话》的核心定律。通常来说，人越多效率越低。但在这个团队，人数翻倍，人均产出反而加速了。</p><p>为什么？因为新人的角色变了：</p><table tabindex="0"><thead><tr><th>传统开发</th><th>Harness 开发</th></tr></thead><tbody><tr><td>新人是来流水线上拧螺丝的</td><td>新人是来升级流水线的</td></tr></tbody></table><p>当你的工作是改进基础设施时，你的每一分投入都会通过 Agent 的执行力被放大成千上万倍。</p><hr><h2 id="vibe-coding-与深度优先" tabindex="-1">Vibe Coding 与深度优先 <a class="header-anchor" href="#vibe-coding-与深度优先" aria-label="Permalink to &quot;Vibe Coding 与深度优先&quot;">​</a></h2><p>具体怎么做？把一个大目标拆解成一个个小的构建模块：设计、编码、审查、测试，然后让 Agent 逐个完成这些模块，再用它们去解锁更复杂的任务。</p><p>Vibe Coding 概念来自独立开发者 Jeffrey Hunley——把 AI Agent 放进一个循环里，给他一个目标，让他反复执行编码、审查、测试、修复，直到循环跑通为止。</p><p>工程师描述一个任务，启动 Agent，然后 Agent 自己开一个 Pull Request。接下来，为了让这个 PR 推到完成，他们会让 Agent 先在本地自我审查，再请求 Agent 在本地和云端分别做额外的审查，然后根据反馈自动修改，循环往复，直到所有 Agent 审查者都满意为止。</p><p>随着时间推移，他们已经把<strong>几乎所有的代码审查工作都交给了 Agent 之间互相审查</strong>。人类甚至不需要审查这些 PR。</p><hr><h2 id="失败时的处理原则" tabindex="-1">失败时的处理原则 <a class="header-anchor" href="#失败时的处理原则" aria-label="Permalink to &quot;失败时的处理原则&quot;">​</a></h2>',29)),(A(),r(B,null,{default:n(()=>[o(a,{id:"mermaid-113",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E6%89%A7%E8%A1%8C%E4%BB%BB%E5%8A%A1%5D%20--%3E%20B%7B%E4%BB%BB%E5%8A%A1%E5%AE%8C%E6%88%90%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%7C%20C%5B%E5%90%88%E5%B9%B6%E4%BB%A3%E7%A0%81%5D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%7C%20D%7B%E5%8D%A1%E5%9C%A8%E6%96%B9%E5%90%91%E6%80%A7%E6%8A%89%E6%8B%A9%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%5B%E6%8C%89%E9%93%83%E5%8F%AB%E4%BA%BA%E7%B1%BB%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20F%5B%E8%AF%8A%E6%96%AD%E7%BC%BA%E4%BB%80%E4%B9%88%E8%83%BD%E5%8A%9B%5D%0A%20%20%20%20F%20--%3E%20G%5B%E8%A1%A5%E5%85%85%E5%88%B0%E7%8E%AF%E5%A2%83%2F%E5%B7%A5%E5%85%B7%2F%E6%96%87%E6%A1%A3%5D%0A%20%20%20%20G%20--%3E%20A%0A%20%20%20%20E%20--%3E%20H%5B%E4%BA%BA%E7%B1%BB%E5%86%B3%E7%AD%96%E5%90%8E%E9%87%8D%E5%90%AF%5D%0A%20%20%20%20H%20--%3E%20A%0A"})]),fallback:n(()=>[...t[1]||(t[1]=[e(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=s('<blockquote><p>💡 <strong>图解：</strong> Agent 失败后绝不&quot;再试一次&quot;，而是诊断环境缺口——补的是基建，不是手把手教。</p></blockquote><p>失败时，修复手段几乎从来不是「再试一次」，而是回到原问题：缺了什么能力？如何让这个能力对 Agent 既清晰又可执行？</p><p>这种深度优先的思路确保了每一个构建模块都是稳固的。Agent 不会因为一次失败就放弃，而是会从失败中学习，调整策略，直到找到正确的路径。</p><hr><blockquote><p><strong>Harness Engineering 的重要性正在凸显。</strong> 当代码可以被无限生成，工程师的价值就从&quot;写代码&quot;迁移到了&quot;设计让代码产生的环境&quot;。你不再是泥瓦匠，你是系统设计师。</p></blockquote><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Agent 写不出好代码不是因为笨，而是因为&quot;瞎&quot;——环境定义不足</li><li>工程师角色从泥瓦匠转变为系统设计师</li><li>Harness 工程师核心三件事：设计环境、明确意图、构建反馈</li><li>代码从昂贵资产变为廉价编译产物，等待成本取代修正成本成为瓶颈</li><li>Vibe Coding：让 Agent 在编码-审查-测试的循环中自主完成任务</li></ul><p><strong>下一章</strong>: <a href="./02-让Agent拥有感官.html">让Agent拥有感官</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/02-上下文工程/">下一模块: 上下文工程 →</a></p>',11))])}const _=l(p,[["render",d]]);export{m as __pageData,_ as default};
